const baseUrl = env.get('AI_INSIGHT_BASE_URL') || 'http://ai-insight-service:8080';
const action = msg.data?.recordDetails?.action;
const params = msg.data?.recordDetails?.params || {};

// Store original data for response routing
msg.originalData = msg.data;

if (action === 'load-latest') {
    msg.url = baseUrl + '/api/v1/insights/latest';
    msg.method = 'GET';
    msg.payload = '';
} else if (action === 'energy-summary') {
    msg.url = baseUrl + '/api/v1/insights/energy-summary';
    msg.method = 'POST';
    msg.payload = {
        start_ts: params.start_ts,
        end_ts: params.end_ts,
        timezone: params.timezone || 'UTC',
        forecast_alpha: 0.6,
        trend_epsilon: 0.02,
        daily_overview_strategy: 'fallback_hourly',
        include_data: true
    };
} else if (action === 'anomaly-report') {
    msg.url = baseUrl + '/api/v1/insights/anomaly-report';
    msg.method = 'POST';
    msg.payload = {
        start_ts: params.start_ts,
        end_ts: params.end_ts,
        timezone: params.timezone || 'UTC',
        robust_z_threshold: 3.5,
        include_data: true
    };
} else if (action === 'city-status') {
    msg.url = baseUrl + '/api/v1/insights/city-status';
    msg.method = 'POST';
    msg.payload = {
        start_ts: params.start_ts,
        end_ts: params.end_ts,
        timezone: params.timezone || 'UTC',
        include_data: true
    };
} else {
    node.warn('Unknown action: ' + action);
    return null;
}

msg.headers = {
    'Content-Type': 'application/json',
    'x-agreement-id': 'agreement-ui',
    'x-asset-id': 'asset-ui',
    'x-user-roles': 'ai_insight_consumer'
};

return msg;

const statusCode = msg.statusCode;
const originalAction = msg.originalData?.recordDetails?.action;

// Handle errors
if (statusCode >= 400 || !msg.payload) {
    msg.data = {
        topic: 'error',
        recordDetails: {
            message: msg.payload?.detail || 'AI Insight Service returned error ' + statusCode,
            action: originalAction
        }
    };
    msg._socketId = msg.originalData?.session?._socketId;
    return msg;
}

// Handle latest insights response
if (originalAction === 'load-latest') {
    msg.data = {
        topic: 'latest.response',
        recordDetails: {
            latest: msg.payload.latest || msg.payload
        }
    };
    msg._socketId = msg.originalData?.session?._socketId;
    return msg;
}

// Handle standard insight responses (InsightResponse schema)
const response = msg.payload;
msg.data = {
    topic: 'insight.response',
    recordDetails: {
        action: originalAction,
        insight: {
            type: response.insight_type,
            summary: response.summary,
            keyFindings: response.key_findings,
            recommendations: response.recommendations,
            metadata: response.metadata,
            data: response.data || null
        }
    }
};
msg._socketId = msg.originalData?.session?._socketId;
return msg;
